/*
    * @name AddOrUpdateLocation
    * @date 19.01.2021
    * @author Isro Syaeful
    * @param ucId (STRING)
    * @param locId (STRING)
    * @param coordinate (STRING)
    * @param locationName (STRING)
    * @param locationDescription (STRING)
    * @param companyName (STRING)
    * @return location thing infotable
    *
    * add or update location thing based on locId and ucId
    */
    var result;
    var loggerBeginning = "[HPMC.Core.Manager:AddOrUpdateLocation] ";

    (function(){
        "use strict";
        try{
            logger.info(loggerBeginning + " Start to Add or update location thing ");
            timezoneOffset = (timezoneOffset===undefined)?0:timezoneOffset;
            let locationThingName;
            let locationFiltered = ThingTemplates["HPMC.Core.Location.TT"].QueryImplementingThingsWithData({
                maxItems: undefined /* NUMBER */,
                tags: undefined /* TAGS */,
                nameMask: undefined /* STRING */,
                query: {
                    "filters": {
                        "type": "And",
                        "filters": [
                            {
                                "type": "LIKE",
                                "fieldName": "locId",
                                "value": locId
                            },
                            {
                                "type": "LIKE",
                                "fieldName": "ucId",
                                "value": ucId
                            }
                        ]
                    }
    			} /* QUERY */
            });//QueryImplementingThingsWithData({}); 
            if (locationFiltered.length<1){
                try{
                    logger.info (loggerBeginning + " create location thing");
                	locationThingName = me.CreateLocation();
                }catch(err1){
                    locationThingName = "";
                    logger.error (loggerBeginning + " cant create location thing - [ERROR]:"+err1);
                }
            } else{
                locationThingName=locationFiltered.name;
            }        
            //logger.info(loggerBeginning + " new thing name = " + locationThingName);

            Things[locationThingName].caption = locationName;
            Things[locationThingName].companyName = companyName;
            Things[locationThingName].location = coordinate;
            Things[locationThingName].ucId = ucId;
            Things[locationThingName].locId = locId;
            Things[locationThingName].address = address;
            Things[locationThingName].timezoneOffset = timezoneOffset;
            Things[locationThingName].hasDST = hasDST;
            Things[locationThingName].standardTimezoneOffset = standardTimezoneOffset;
            let tempDesc = Things[locationThingName].description.split(':')[0];
            Things[locationThingName].SetDescription({
                    description: tempDesc+ " : "+locationDescription /* STRING */
                });
            result = Things[locationThingName].GetPropertyValues();

        }catch(e){
            logger.error(loggerBeginning +"Failed to add/update the location - [ERROR]: "+e);   
        }
    }());


/*
    * @name CreateLocation
    * @date 03.09.2020
    * @author Georg Reckendorfer
    * @return thingname - name of the thing(location) which have been created
    *
    * Create a asset at the given location in the given group.
    */
    var loggerBeginning = "[HPMC.Core.Manager:CreateLocation] ";

    logger.info(loggerBeginning + "Create new location.");

    var projectName = "HPMC.DynamicData";
    var locationTemplatename = "HPMC.Core.Location.TT";

    var dateTime = dateFormat(new Date(), "yyyy-MM-dd HH:mm 'GMT'Z");
    var descriptionText = "created in ThingWorx on "+ dateTime +" by " +Resources["CurrentSessionInfo"].GetCurrentUser();
    var locationThingname = "HPMC.Location." + generateGUID(); //me.CreateGUID();

    var newCreatedCaption = "New Location (" + dateTime +")";

    var newLocationThing;
    var result; //THINGNAME - HPMC.Core.Location.DS

    //check if locationThingname does already exist
    newLocationThing = Things[locationThingname];
    while(newLocationThing !== null){
        logger.info(loggerBeginning + "Create new locationname, because location with name " + locationThingname + "does already exist.");
        locationThingname = "HPMC.Location." + generateGUID(); //me.CreateGUID();
        newLocationThing = Things[locationThingname];
    }

    try{
        Resources["EntityServices"].CreateThing({
            name: locationThingname /* STRING */,
            description: descriptionText /* STRING */,
            thingTemplateName: locationTemplatename /* THINGTEMPLATENAME */,
            tags: undefined /* TAGS */
        });
    	logger.info(loggerBeginning + " AFTER CREATETHING - new locatinThingname = " + locationThingname);
        //newLocationThing = Things[locationThingname];

        Things[locationThingname].EnableThing();
        Things[locationThingname].RestartThing();

        Things[locationThingname].SetProjectName({
            projectName: projectName /* PROJECTNAME */
        });

        Things[locationThingname].caption = newCreatedCaption;
    	logger.info(loggerBeginning + " new thing caption = " + Things[locationThingname].name);
        result = Things[locationThingname].name;
    }catch(e){
        Resources["EntityServices"].DeleteThing({
            name: locationThingname /* STRING */
        });

        logger.error(loggerBeginning +"Failed to create the location: " + e);   
    }


