/**
 * @name generateUserGroups
 * @date 18.03.2021
 * @author Christian Krenkel
 * creates the user groups and assigns them to the OU. See Roles and Rights document.
 * 	e.g [region][.subRegion].UC[ucId].[companyName].LOC[locId].[locationName] and higher groups
 *
 * @param region			the region in the orgTree (e.g. CE, APAC)
 * @param subRegion		subregion (ONLY in APAC, e.g. SC)
 * @param locId			location id
 * @param ucId			company id
 * @param locationName	location name (e.g. Mitry, Dongguan)
 * @param companyName	company name (e.g. BUF, ADG)
 *
 * @return NOTHING
 */

const UG_DESCRIPTION = "created by Service generateUserGroups (" + dateFormat(new Date(), "yyyy-MM-dd HH:mm 'GMT'Z") + ") by " + Resources["CurrentSessionInfo"].GetCurrentUser();

(function () {
    const UC_PREFIX = "UC";
    const LOC_PREFIX = "LOC";
    const withSubRegion = subRegion !== undefined && subRegion !== "";

    let groupArray = [
        // group for location
        region + (withSubRegion ? "." + subRegion : "") + "." + UC_PREFIX + ucId + "." + companyName + "." + LOC_PREFIX + locId + "." + locationName,
        // group for company
        region + (withSubRegion ? "." + subRegion : "") + "." + UC_PREFIX + ucId + "." + companyName
    ];

    if (withSubRegion) {
        groupArray.push(region + "." + subRegion);
    }
    // group for region
    groupArray.push(region);

    var previouslyCreated = [];
    for (let i = 0; i < groupArray.length; i++) {
        previouslyCreated[i] = createGroup("HPMC." + groupArray[i] + ".UG");
        // add group to parent if parent was created previously
        logger.info("prev created: " + "HPMC." + groupArray[i] + ".UG" + " | " + previouslyCreated[i]);
        if (i > 0 && previouslyCreated[i - 1] && previouslyCreated[i]) {
            logger.info("child: " + "HPMC." + groupArray[i] + ".UG" + " parent: " + "HPMC." + groupArray[i - 1] + ".UG");
            addGroupToParent("HPMC." + groupArray[i] + ".UG", "HPMC." + groupArray[i - 1] + ".UG");
        }
        if (previouslyCreated[i]) {
            // generate base roles (Administrator, Supervisor, Operator, Display) for location UG
            if (i == 0) {
                if (createGroup("HPMC." + groupArray[i] + ".Administrator.UG")) {
                    // add location[role] group and add it to the OU
                    addGroupToParent("HPMC." + groupArray[i] + ".Administrator.UG", "HPMC." + groupArray[i] + ".UG");
                    addGroupToOrganization("HPMC." + groupArray[i] + ".Administrator.UG", groupArray[i]);
                    // add location[role] group to the screengroup
                    addGroupToParent("HPMC." + groupArray[i] + ".Administrator.UG", "HPMC.Administrator.UG");
                }
                if (createGroup("HPMC." + groupArray[i] + ".Supervisor.UG")) {
                    // add location[role] group and add it to the OU
                    addGroupToParent("HPMC." + groupArray[i] + ".Supervisor.UG", "HPMC." + groupArray[i] + ".UG");
                    addGroupToOrganization("HPMC." + groupArray[i] + ".Supervisor.UG", groupArray[i]);
                    // add location[role] group to the screengroup
                    addGroupToParent("HPMC." + groupArray[i] + ".Supervisor.UG", "HPMC.Supervisor.UG");
                }
                if (createGroup("HPMC." + groupArray[i] + ".Operator.UG")) {
                    // add location[role] group and add it to the OU
                    addGroupToParent("HPMC." + groupArray[i] + ".Operator.UG", "HPMC." + groupArray[i] + ".UG");
                    addGroupToOrganization("HPMC." + groupArray[i] + ".Operator.UG", groupArray[i]);
                    // add location[role] group to the screengroup
                    addGroupToParent("HPMC." + groupArray[i] + ".Operator.UG", "HPMC.Operator.UG");
                }
                if (createGroup("HPMC." + groupArray[i] + ".Display.UG")) {
                    // add location[role] group and add it to the OU
                    addGroupToParent("HPMC." + groupArray[i] + ".Display.UG", "HPMC." + groupArray[i] + ".UG");
                    addGroupToOrganization("HPMC." + groupArray[i] + ".Display.UG", groupArray[i]);
                    // add location[role] group to the screengroup
                    addGroupToParent("HPMC." + groupArray[i] + ".Display.UG", "HPMC.Display.UG");
                }
            } else {
                // Add all managers to their respective UGs
                if (createGroup("HPMC." + groupArray[i] + ".Manager.UG")) {
                    addGroupToParent("HPMC." + groupArray[i] + ".Manager.UG", "HPMC." + groupArray[i] + ".UG");
                }

                // add location[role] group to the screengroup & to OrgUnit depending there hirarchie
                if (i === 1) {
                    addGroupToParent("HPMC." + groupArray[i] + ".Manager.UG", "HPMC.CompanyManager.UG");
                    addGroupToOrganization("HPMC." + groupArray[i] + ".Manager.UG", groupArray[i]);
                } else if (i === 2 && withSubRegion) {
                    addGroupToParent("HPMC." + groupArray[i] + ".Manager.UG", "HPMC.SubregionalManager.UG");
                    addGroupToOrganization("HPMC." + groupArray[i] + ".Manager.UG", "Region." + groupArray[i]);
                } else {
                    addGroupToParent("HPMC." + groupArray[i] + ".Manager.UG", "HPMC.RegionalManager.UG");
                    addGroupToOrganization("HPMC." + groupArray[i] + ".Manager.UG", "Region." + groupArray[i]);
                }
            }
        }
    }

    // result: INFOTABLE dataShape: "RootEntityList"
    const locations = ThingTemplates["HPMC.Core.Location.TT"].QueryImplementingThingsWithData({
        query: {
            filters: {
                type: "And",
                filters: [
                    { type: "EQ", fieldName: "ucId", value: ucId },
                    { type: "EQ", fieldName: "locId", value: locId }
                ]
            }
        }
    });

    if (locations.rows.length !== 1) {
        // error
        logger.error("multiple or no Location found to assign groups");
        return;
    }
    // set access group for later asset assignments
    Things[locations[0].name].runtimeAccessGroup = "HPMC." + groupArray[0] + ".UG";

    addRuntimePermissionsToThing(locations[0].name, "HPMC." + groupArray[0] + ".UG");
    //    Things[locations[0].name].AddVisibilityPermission({
    //        principal: "HPMC.Voestalpine.Orga:" + groupArray[0] /* STRING */,
    //        principalType: "OrganizationalUnit" /* STRING */
    //    });

    locations[0].assetGroups.rows.toArray().forEach((assetGroup) => {
        assetGroup.assets.rows.toArray().forEach((asset) => {
            addRuntimePermissionsToThing(asset.assetThingname, "HPMC." + groupArray[0] + ".UG");
        });
    });
})();

// creates group if not already exists
function createGroup(groupName) {
    if (Groups[groupName] === null) {
        try {
            Resources["EntityServices"].CreateGroup({
                name: groupName /* STRING */,
                description: UG_DESCRIPTION /* STRING */,
                projectName: undefined /* PROJECTNAME */,
                tags: undefined /* TAGS */
            });
        } catch (err) {
            Resources["EntityServices"].DeleteGroup({
                name: groupName /* STRING */
            });
            logger.error("Group " + groupName + " deleted: " + err);
            return false;
        }
        logger.info(groupName + " | created");
        return true;
    } else {
        logger.error(groupName + " | already exists" + Groups[groupName]);
        return false;
    }
}

// adds group to parent group if this group not already exists
function addGroupToParent(groupName, parent) {
    if (Groups[parent] !== null) {
        Groups[parent].AddMember({
            member: groupName /* STRING */,
            type: "Group" /* STRING */
        });
    } else {
        logger.error(groupName + " not added to parent " + parent);
    }
}

function addGroupToOrganization(groupName, org) {
    let orgChange = org;
    // region is the only part where the default construction of the org path is not unified with the org layout
    // so we have to check here if only the region exists so we can add 'Region' before the region definition
    if (org.split(".").length == 1) {
        orgChange = "Region." + org;
    }
    Organizations[me.GetMainOrganizationName()].AddMember({
      name: orgChange /* STRING */,
      member: groupName /* STRING */,
      type: "Group" /* STRING */
    });
}

function addRuntimePermissionsToThing(thingName, groupName) {
    if (Things[thingName] === null) {
        logger.warn("could not add runtime permissions to Thing {}", thingName);
        return;
    }

    Things[thingName].AddRunTimePermission({
        principal: groupName /* STRING */,
        allow: true /* BOOLEAN */,
        resource: "*" /* STRING */,
        type: "PropertyRead" /* STRING */,
        principalType: "Group" /* STRING */
    });
    Things[thingName].AddRunTimePermission({
        principal: groupName /* STRING */,
        allow: true /* BOOLEAN */,
        resource: "*" /* STRING */,
        type: "ServiceInvoke" /* STRING */,
        principalType: "Group" /* STRING */
    });
}


/*
 * @name GetLocationById
 * @date 03.04.2024
 * @author Dan Zielinsky
 */

const result = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
    dataShapeName: "HPMC.Core.Location.DS"
});

// CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(EntityList)
const propertyNames = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({ dataShapeName: "EntityList" });
propertyNames.AddRow({ name: "locId" });

// result: INFOTABLE dataShape: "RootEntityList"
const location = ThingTemplates["HPMC.Core.Location.TT"].QueryImplementingThingsOptimized({
    networkName: undefined /* STRING */,
    networkParentNode: undefined /* STRING */,
    networkMaxDepth: undefined /* INTEGER {"defaultValue":0} */,
    maxItems: 1 /* NUMBER {"defaultValue":500} */,
    basicPropertyNames: undefined /* INFOTABLE {"dataShape":"EntityList"} */,
    withPermissions: false /* BOOLEAN {"defaultValue":false} */,
    offset: 0 /* NUMBER {"defaultValue":0} */,
    nameMask: undefined /* STRING */,
    propertyNames: propertyNames /* INFOTABLE {"dataShape":"EntityList"} */,
    query: { filters: { type: "EQ", fieldName: "locId", value: locId } } /* QUERY */,
    tags: undefined /* TAGS */
});

if (Things[location.name]) {
    // HPMC.Core.Location.DS entry object
    result.AddRow({
        address: Things[location.name].address, // STRING
        caption: Things[location.name].caption, // STRING
        location: Things[location.name].location, // LOCATION
        locId: Things[location.name].locId, // STRING
        ucId: Things[location.name].ucId, // STRING
        assetGroups: Things[location.name].assetGroups, // INFOTABLE {"dataShape":"HPMC.Core.Asset.Group.DS"}
        toolGroups: Things[location.name].toolGroups, // INFOTABLE {"dataShape":"HPMC.Core.Tool.Group.DS"}
        materialGroups: Things[location.name].materialGroups, // INFOTABLE {"dataShape":"HPMC.Core.Material.Group.DS"}
        name: Things[location.name].name, // STRING [Primary Key]
        avatar: Things[location.name].avatar, // IMAGELINK
        companyName: Things[location.name].companyName, // STRING
        timezoneOffset: Things[location.name].timezoneOffset // INTEGER
    });
}


