/**
    * @name SetRolesAndRightsForAssets
    * @date 29.04.2021
    * @author Christian Krenkel
    * assigns the Usergroup to all assigned assets
    * 
    * @param locId			location id
    * @param ucId			company id
    *
    * @return NOTHING
    */

    (function() {
        // result: INFOTABLE dataShape: "RootEntityList"
        const locations = ThingTemplates["HPMC.Core.Location.TT"].QueryImplementingThingsWithData({
            query:  {"filters": {
                "type": "And",
                "filters": [
                    {"type":"EQ","fieldName":"ucId","value":ucId},
                    {"type":"EQ","fieldName":"locId","value":locId}
                ]
            }}
        });

        if (locations.rows.length !== 1) {
            // error
            logger.error("multiple or no Location found to assign permissions to assets");
            throw "multiple or no Location found to assign permissions to assets";
        }

        if (locations[0].runtimeAccessGroup === null || locations[0].runtimeAccessGroup === undefined || locations[0].runtimeAccessGroup === "") {
            logger.error("unknown usergroup to set for the asset runtime permissions");
            throw "unknown usergroup to set for the asset runtime permissions";
        }

        locations[0].assetGroups.rows.toArray().forEach(assetGroup => {
            assetGroup.assets.rows.toArray().forEach(asset => {
                addRuntimePermissionsToThing(asset.assetThingname, locations[0].runtimeAccessGroup);
            });
        });
    })();

    function addRuntimePermissionsToThing(thingName, groupName) {
        if (Things[thingName] === null) {
            logger.warn("could not add runtime permissions to Thing {}", thingName);
            return;
        }

        Things[thingName].AddRunTimePermission({
            principal: groupName /* STRING */,
            allow: true /* BOOLEAN */,
            resource: "*" /* STRING */,
            type: "PropertyRead" /* STRING */,
            principalType: "Group" /* STRING */
        });
        Things[thingName].AddRunTimePermission({
            principal: groupName /* STRING */,
            allow: true /* BOOLEAN */,
            resource: "*" /* STRING */,
            type: "ServiceInvoke" /* STRING */,
            principalType: "Group" /* STRING */
        });
    }


