/*
    * @name UpdateLocations
    * @date 18.08.2020
    * @author Georg Reckendorfer
    * Takes an infotable as input and updates all locations based on the information from the input-infoTable.
    */

    logger.info("[HPMC.Core.Manager:UpdateLocations]: Update all locations which are includeed in the input-infotable.");

    var editedLocationThingname;

    try{
        for(var i = 0; i < editedLocationTable.getRowCount(); i++){
            editedLocationThing = Things[editedLocationTable[i].name];

            editedLocationThing.address = editedLocationTable[i].address;
            editedLocationThing.caption = editedLocationTable[i].caption;
            editedLocationThing.location = editedLocationTable[i].location;
            editedLocationThing.locId = editedLocationTable[i].locId;
            editedLocationThing.ucId = editedLocationTable[i].ucId;
            editedLocationThing.companyName = editedLocationTable[i].companyName;
        }
    } catch(e){
     	logger.error(e);   
    }
